'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/utils/supabase/client';
import { Eye, EyeOff, Lock, Mail, ArrowRight, MapPin, Phone, User } from 'lucide-react';
import Link from 'next/link';

export default function LoginPage() {
  const router = useRouter();
  const supabase = createClient();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showPassword, setShowPassword] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [city, setCity] = useState('');
  const [phone, setPhone] = useState('');

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (isRegistering) {
      const { error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            full_name: fullName,
            city: city,
            phone: phone,
          },
        },
      });
      if (error) {
        setError(error.message);
        setLoading(false);
      } else {
        // Determine if email confirmation is required based on project settings
        // For now, assume auto-login or redirect
        router.push('/dashboard');
        router.refresh();
      }
    } else {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error) {
        setError(error.message);
        setLoading(false);
      } else {
        router.push('/dashboard');
        router.refresh();
      }
    }
  };

  const handleGoogleLogin = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: `${location.origin}/auth/callback`,
      },
    });
    if (error) setError(error.message);
  };

  return (
    <div className="login-container">
      <div className="glass-panel login-card">
        <div className="login-header">
          <Link href="/" className="logo-link">
            <img src="/logo-transparent.png" alt="Greenland" className="logo" />
            <div className="logo-text">
              <span>GREENLAND</span>
              <small>PRODUCTS</small>
            </div>
          </Link>
          <h2>{isRegistering ? 'Crear Cuenta' : 'Bienvenido de nuevo'}</h2>
          <p>{isRegistering ? 'Regístrate para comenzar' : 'Accede a tu portal de distribuidor'}</p>
        </div>

        {error && (
          <div className="error-alert">
            {error}
          </div>
        )}

        <form onSubmit={handleAuth} className="login-form">
          {isRegistering && (
            <>
              <div className="form-group">
                <label>Nombre Completo</label>
                <div className="input-wrapper">
                  <User className="input-icon" size={20} />
                  <input
                    type="text"
                    placeholder="Juan Pérez"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    required
                  />
                </div>
              </div>
              <div className="form-group">
                <label>Ciudad</label>
                <div className="input-wrapper">
                  <MapPin className="input-icon" size={20} />
                  <input
                    type="text"
                    placeholder="Monterrey, NL"
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    required
                  />
                </div>
              </div>
              <div className="form-group">
                <label>Teléfono Celular</label>
                <div className="input-wrapper">
                  <Phone className="input-icon" size={20} />
                  <input
                    type="tel"
                    placeholder="81 1234 5678"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required
                  />
                </div>
              </div>
            </>
          )}
          <div className="form-group">
            <label>Correo Electrónico</label>
            <div className="input-wrapper">
              <Mail className="input-icon" size={20} />
              <input
                type="email"
                placeholder="ejemplo@empresa.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label>Contraseña</label>
            <div className="input-wrapper">
              <Lock className="input-icon" size={20} />
              <input
                type={showPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
              <button
                type="button"
                className="toggle-password"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
          </div>

          <button type="submit" className="btn btn-primary btn-block" disabled={loading}>
            {loading ? 'Procesando...' : (isRegistering ? 'Registrarse' : 'Ingresar')}
            {!loading && <ArrowRight size={20} />}
          </button>
        </form>

        <div className="divider">
          <span>O continúa con</span>
        </div>

        <button onClick={handleGoogleLogin} className="btn btn-glass btn-block google-btn">
          <svg className="google-icon" viewBox="0 0 24 24">
            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
          </svg>
          Google
        </button>

        <p className="auth-footer">
          {isRegistering ? '¿Ya tienes cuenta?' : '¿No tienes cuenta?'}
          <button
            onClick={() => setIsRegistering(!isRegistering)}
            className="text-primary btn-link ml-2"
            style={{ background: 'none', border: 'none', cursor: 'pointer', paddingLeft: '0.5rem', fontWeight: 600 }}
          >
            {isRegistering ? 'Inicia Sesión' : 'Solicita acceso'}
          </button>
        </p>
      </div>

      <style jsx>{`
        .login-container {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 2rem;
          background-image: url('https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80');
          background-size: cover;
          background-position: center;
          position: relative;
        }

        .login-container::before {
          content: '';
          position: absolute;
          inset: 0;
          background: rgba(15, 15, 26, 0.85);
          backdrop-filter: blur(8px);
        }

        .login-card {
          width: 100%;
          max-width: 420px;
          padding: 3rem;
          position: relative;
          z-index: 10;
        }

        .login-header {
          text-align: center;
          margin-bottom: 2.5rem;
        }

        .logo-link {
          display: inline-flex;
          align-items: center;
          gap: 1rem;
          margin-bottom: 2rem;
          text-decoration: none;
        }

        .logo {
          width: 48px;
          height: auto;
        }

        .logo-text {
          display: flex;
          flex-direction: column;
          align-items: flex-start;
          color: white;
        }
        .logo-text span {
          font-weight: 800;
          font-size: 1.2rem;
          line-height: 1;
        }
        .logo-text small {
          font-size: 0.75rem;
          color: var(--color-primary);
          letter-spacing: 0.1em;
        }

        .login-header h2 {
          font-size: 1.75rem;
          margin-bottom: 0.5rem;
          color: white;
        }

        .login-header p {
          color: var(--color-text-muted);
        }

        .form-group {
          margin-bottom: 1.5rem;
        }

        .form-group label {
          display: block;
          margin-bottom: 0.5rem;
          color: var(--color-text-p);
          font-size: 0.9rem;
        }

        .input-wrapper {
          position: relative;
        }

        .input-icon {
          position: absolute;
          left: 1rem;
          top: 50%;
          transform: translateY(-50%);
          color: var(--color-text-muted);
        }

        .input-wrapper input {
          width: 100%;
          padding: 0.875rem 1rem 0.875rem 3rem;
          background: rgba(255, 255, 255, 0.05);
          border: 1px solid rgba(255, 255, 255, 0.1);
          border-radius: var(--radius-md);
          color: white;
          font-size: 1rem;
          transition: all 0.2s;
        }

        .input-wrapper input:focus {
          border-color: var(--color-primary);
          outline: none;
          background: rgba(255, 255, 255, 0.08);
        }

        .toggle-password {
          position: absolute;
          right: 1rem;
          top: 50%;
          transform: translateY(-50%);
          background: none;
          border: none;
          color: var(--color-text-muted);
          cursor: pointer;
        }
        .toggle-password:hover { color: white; }

        .btn-block {
          width: 100%;
          display: flex;
          justify-content: center;
          gap: 0.5rem;
        }

        .divider {
          display: flex;
          align-items: center;
          text-align: center;
          margin: 2rem 0;
          color: var(--color-text-muted);
          font-size: 0.85rem;
        }

        .divider::before,
        .divider::after {
          content: '';
          flex: 1;
          border-bottom: 1px solid rgba(255, 255, 255, 0.1);
        }

        .divider span {
          padding: 0 1rem;
        }

        .google-btn {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 0.75rem;
          font-weight: 500;
        }

        .google-icon {
          width: 20px;
          height: 20px;
        }

        .auth-footer {
          margin-top: 2rem;
          text-align: center;
          font-size: 0.9rem;
          color: var(--color-text-muted);
        }

        .error-alert {
          background: rgba(239, 68, 68, 0.1);
          border: 1px solid rgba(239, 68, 68, 0.2);
          color: #fca5a5;
          padding: 0.75rem;
          border-radius: var(--radius-md);
          margin-bottom: 1.5rem;
          font-size: 0.9rem;
        }
      `}</style>
    </div>
  );
}
